
import { Toaster } from "@/components/ui/toaster";
import { Toaster as Sonner } from "@/components/ui/sonner";
import { TooltipProvider } from "@/components/ui/tooltip";
import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import { LanguageProvider } from "@/contexts/LanguageContext";
import { AuthProvider, useAuth } from "@/contexts/AuthContext";
import Index from "./pages/Index";
import About from "./pages/About";
import Careers from "./pages/Careers";
import Blog from "./pages/Blog";
import BlogPost from "./pages/BlogPost";
import Diagnostic from "./pages/Diagnostic";
import CalculadoraValorHora from "./pages/CalculadoraValorHora";
import NotaFiscalMei from "./pages/NotaFiscalMei";
import PrecificarServicos from "./pages/PrecificarServicos";
import Privacy from "./pages/Privacy";
import Terms from "./pages/Terms";
import NotFound from "./pages/NotFound";
import CookieConsent from "./components/CookieConsent";
import WhatsAppButton from "./components/WhatsAppButton";
import SEO from "./components/SEO";
import { lazy, Suspense } from "react";

const Admin = lazy(() => import("./pages/Admin"));

const queryClient = new QueryClient();

const ProtectedAdminRoute = ({ children }: { children: React.ReactNode }) => {
  const { isAuthenticated, isAdmin, loading } = useAuth();
  if (loading) return <div className="min-h-screen bg-[#1a1a1a] flex items-center justify-center text-white">Loading...</div>;
  return <>{children}</>;
};

// Redirect to the live app for former waitlist / coming-soon URLs.
const AppRedirect = () => {
  if (typeof window !== 'undefined') {
    window.location.replace('https://www.eluvie.app/');
  }
  return null;
};

// PT-BR routes (mounted at '/'). Uses Portuguese slugs and redirects legacy
// English slugs so old links keep working.
const PtRoutes = () => (
  <Routes>
    <Route index element={<Index />} />
    <Route path="sobre-nos" element={<About />} />
    <Route path="carreiras" element={<Careers />} />
    <Route path="em-breve" element={<AppRedirect />} />
    <Route path="blog" element={<Blog />} />
    <Route path="blog/:slug" element={<BlogPost />} />
    <Route path="diagnostico" element={<Diagnostic />} />
    <Route path="calculadora-valor-hora" element={<CalculadoraValorHora />} />
    <Route path="nota-fiscal-mei" element={<NotaFiscalMei />} />
    <Route path="precificar-servicos" element={<PrecificarServicos />} />
    <Route path="privacidade" element={<Privacy />} />
    <Route path="termos" element={<Terms />} />
    {/* Legacy EN slug redirects (preserve previously indexed URLs). */}
    <Route path="about" element={<Navigate to="/sobre-nos" replace />} />
    <Route path="careers" element={<Navigate to="/carreiras" replace />} />
    <Route path="coming-soon" element={<AppRedirect />} />
    <Route path="diagnostic" element={<Navigate to="/diagnostico" replace />} />
    <Route path="privacy" element={<Navigate to="/privacidade" replace />} />
    <Route path="terms" element={<Navigate to="/termos" replace />} />
    <Route path="hourly-rate-calculator" element={<Navigate to="/calculadora-valor-hora" replace />} />
    <Route path="pricing-your-services" element={<Navigate to="/precificar-servicos" replace />} />
    <Route path="*" element={<NotFound />} />
  </Routes>
);

// EN routes (mounted at '/en'). Uses English slugs.
const EnRoutes = () => (
  <Routes>
    <Route index element={<Index />} />
    <Route path="about" element={<About />} />
    <Route path="careers" element={<Careers />} />
    <Route path="coming-soon" element={<AppRedirect />} />
    <Route path="blog" element={<Blog />} />
    <Route path="blog/:slug" element={<BlogPost />} />
    <Route path="diagnostic" element={<Diagnostic />} />
    <Route path="hourly-rate-calculator" element={<CalculadoraValorHora />} />
    <Route path="nota-fiscal-mei" element={<NotaFiscalMei />} />
    <Route path="pricing-your-services" element={<PrecificarServicos />} />
    <Route path="privacy" element={<Privacy />} />
    <Route path="terms" element={<Terms />} />
    {/* Legacy PT-slug redirects on the EN side. */}
    <Route path="calculadora-valor-hora" element={<Navigate to="/en/hourly-rate-calculator" replace />} />
    <Route path="precificar-servicos" element={<Navigate to="/en/pricing-your-services" replace />} />
    <Route path="*" element={<NotFound />} />
  </Routes>
);

const AppRoutes = () => (
  <Suspense fallback={<div className="min-h-screen bg-[#1a1a1a]" />}>
    <Routes>
      {/* Admin stays language-agnostic */}
      <Route
        path="/admin"
        element={
          <ProtectedAdminRoute>
            <Admin />
          </ProtectedAdminRoute>
        }
      />
      <Route path="/en/*" element={<EnRoutes />} />
      <Route path="/*" element={<PtRoutes />} />
    </Routes>
  </Suspense>
);

const App = () => (
  <QueryClientProvider client={queryClient}>
    <AuthProvider>
      <TooltipProvider>
        <Toaster />
        <Sonner />
        <BrowserRouter>
          <LanguageProvider>
            <SEO />
            <AppRoutes />
            <CookieConsent />
            <WhatsAppButton />
          </LanguageProvider>
        </BrowserRouter>
      </TooltipProvider>
    </AuthProvider>
  </QueryClientProvider>
);

export default App;
